-- file: functions/groups/competition_start_frozen.sql
-- competition_start_frozen: the single ADR-0037 ruling-4 predicate — is a league's
-- competition start still editable, or has play already begun?
--
-- A league's competition_starts_at may be moved only until the FIRST game eligible under it
-- kicks off; thereafter it is permanently frozen, because moving the line once results are
-- settling would retroactively add or erase them. "Eligible" mirrors the grading boundary
-- (public._participation_start / _grade_games_by_ids): a game counts once
-- game.commence_time >= groups.competition_starts_at. So the start is frozen exactly when some
-- such game's kickoff has already passed:
--
--   exists game g:  g.commence_time >= groups.competition_starts_at  AND  g.commence_time <= now()
--
-- Compared against the same global public.games population grading uses, so the UI's
-- "you can still change this" state can never disagree with what set_competition_start enforces.
--
-- One function rather than the predicate copy-pasted into the writer RPC and the manage-page
-- read: set_competition_start gates on it, and the commissioner console reads it to show or hide
-- the control. SECURITY DEFINER so a member sees the same frozen state grading enforces,
-- regardless of their RLS view of games. Born closed to anon/authenticated by the
-- _close_new_fn_acl event trigger (ADR-0011); granted explicitly in grants/group_grants.sql.
create or replace function public.competition_start_frozen(p_group_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public, pg_temp
as $$
  select exists (
    select 1
    from public.groups grp
    join public.games g
      on g.commence_time >= grp.competition_starts_at
     and g.commence_time <= now()
    where grp.id = p_group_id
  );
$$;

revoke execute on function public.competition_start_frozen(uuid) from public, anon;

-- file: functions/groups/create_group.sql
-- create_group: gated, atomic group creation (ADR-0006, decision 3).
--
-- The whole function runs in a single transaction, so a failure at any step
-- (gate rejection, constraint violation) leaves no orphan group, config, or
-- membership. SECURITY DEFINER lets it write groups / group_config /
-- group_memberships even though those tables block direct client writes; the
-- trust check is the gate below, keyed on the caller's auth.uid().
--
-- p_competition_starts_at (ADR-0037 ruling 5): when competition begins for this league.
-- NULL means "start this week, from now" — the safe default the column already carries
-- (games earlier today are already excluded); a non-NULL value lets the creator start a
-- future week (that week's start_ts). It is clamped UP to now() so a stale or hostile
-- client can never backdate a brand-new league onto games that have already been played —
-- the exact boundary defect ADR-0037 exists to prevent. Moving the start later after
-- creation is the commissioner's job via set_competition_start (ruling 4).
--
-- Error codes (surfaced to the caller as PostgrestError.code):
--   P0001  not authenticated
--   P0010  group name is required
--   P0011  group name too long
--   P0012  group creation not enabled for this account (gated mode)
create or replace function public.create_group(
  p_name text,
  p_competition_starts_at timestamptz default null
)
returns uuid
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_user_id  uuid;
  v_name     text;
  v_mode     text;
  v_capable  boolean;
  v_group_id uuid;
  v_start    timestamptz;
begin
  v_user_id := auth.uid();

  if v_user_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Validate name: non-empty, length-bounded (mirrors groups_name_max_len).
  v_name := btrim(coalesce(p_name, ''));
  if length(v_name) = 0 then
    raise exception 'group name is required' using errcode = 'P0010';
  end if;
  if length(v_name) > 60 then
    raise exception 'group name too long' using errcode = 'P0011';
  end if;

  -- Gate: global mode, then per-user capability when gated.
  select group_creation_mode into v_mode
  from public.settings
  where id = true
  limit 1;
  v_mode := coalesce(v_mode, 'gated');

  if v_mode <> 'open' then
    select can_create_group into v_capable
    from public.users
    where id = v_user_id;

    if not coalesce(v_capable, false) then
      raise exception 'group creation is not enabled for this account'
        using errcode = 'P0012';
    end if;
  end if;

  -- Clamp the competition start up to now(): NULL keeps the column default (now()), and a
  -- provided-but-past value is pulled forward so no already-played game becomes eligible.
  v_start := greatest(now(), coalesce(p_competition_starts_at, now()));

  -- Atomic create: group, then its seeded config, then the creator as commissioner.
  insert into public.groups (name, competition_starts_at)
  values (v_name, v_start)
  returning id into v_group_id;

  -- Seed group_config from global settings, reusing the shape established by
  -- 0213_seed_original_group_config.sql so every group starts consistently.
  insert into public.group_config (group_id, line_source, scoring_rules)
  values (
    v_group_id,
    'fanduel',
    jsonb_build_object(
      'missed_pick_penalty',
      coalesce((select missed_pick_penalty from public.settings where id = true limit 1), -1)
    )
  );

  insert into public.group_memberships (group_id, user_id, role, status)
  values (v_group_id, v_user_id, 'commissioner', 'active');

  return v_group_id;
end;
$$;

revoke execute on function public.create_group(text, timestamptz) from public, anon;

-- file: functions/groups/preview_invite.sql
create or replace function public.preview_invite(p_code text)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_user_id uuid;
  v_invite  public.group_invites%rowtype;
  v_group_name text;
  v_comp_start timestamptz;
  v_start_week int;
begin
  v_user_id := auth.uid();

  if v_user_id is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  -- Read-only preview for the /join/[code] page. Invite SELECT is
  -- commissioner-only under RLS (27_policies_group_invites.sql), so an invitee
  -- cannot see their own invite directly; this SECURITY DEFINER function exposes
  -- only the display state (never the raw row). redeem_invite re-validates
  -- atomically on submit, so this is advisory.
  select * into v_invite
  from public.group_invites
  where code = p_code;

  if not found then
    return jsonb_build_object('status', 'invalid', 'group_name', null);
  end if;

  if v_invite.revoked_at is not null then
    return jsonb_build_object('status', 'revoked', 'group_name', null);
  end if;

  if v_invite.expires_at is not null and v_invite.expires_at < now() then
    return jsonb_build_object('status', 'expired', 'group_name', null);
  end if;

  if v_invite.max_uses is not null and v_invite.used_count >= v_invite.max_uses then
    return jsonb_build_object('status', 'exhausted', 'group_name', null);
  end if;

  if exists (
    select 1 from public.group_memberships
    where group_id = v_invite.group_id and user_id = v_user_id
  ) then
    return jsonb_build_object('status', 'already_member', 'group_name', null);
  end if;

  select name, competition_starts_at into v_group_name, v_comp_start
  from public.groups where id = v_invite.group_id;

  -- The week this invitee would start scoring from (ADR-0037): the first game at or after their
  -- participation start, which for someone joining now is greatest(the league's start, now()).
  -- Drives the "you're in from Week N" onboarding copy. NULL when no eligible game is scheduled
  -- yet (offseason) — the UI falls back to generic copy. Advisory only; grading enforces the
  -- boundary authoritatively.
  select w.week_number into v_start_week
  from public.games g
  join public.weeks w on w.id = g.week_id
  where g.commence_time >= greatest(v_comp_start, now())
  order by g.commence_time asc
  limit 1;

  return jsonb_build_object(
    'status', 'valid',
    'group_name', v_group_name,
    'starts_week_number', v_start_week
  );
end;
$$;

revoke execute on function public.preview_invite(text) from public, anon;

-- file: functions/groups/set_competition_start.sql
-- set_competition_start: commissioner moves when competition begins for the league
-- (ADR-0037 ruling 4). SECURITY DEFINER so it can write groups.competition_starts_at even
-- though the no-client-write policy (25_policies_groups.sql) blocks direct client updates;
-- the is_commissioner check is the trust boundary, mirroring rename_group / update_group_config.
--
-- p_starts_at NULL means "start this week, from now" — resolved to the database's own now(),
-- which is race-free: a client-computed "now" could arrive a few ms behind the server clock and
-- trip the no-backdate guard below, so the client sends NULL and the DB stamps the instant. A
-- non-NULL value is a chosen future week's start_ts.
--
-- Two guards keep the boundary honest:
--   * Frozen once play has begun (competition_start_frozen) — the first eligible game has
--     already kicked off, so moving the start would add or erase settled results.
--   * A non-NULL start may not be in the past — a backdated start would pull already-played
--     games into the boundary and manufacture missed penalties for them, the defect ADR-0037
--     prevents. (NULL sidesteps this: now() is never in the past.)
--
-- Returns the stored competition start so the caller can reflect it without a re-read.
--
-- Error codes (surfaced to the caller as PostgrestError.code):
--   P0001  not authenticated
--   P0020  caller is not a commissioner of the group
--   P0031  competition start is frozen (the first eligible game has kicked off)
--   P0032  competition start cannot be in the past
create or replace function public.set_competition_start(
  p_group_id uuid,
  p_starts_at timestamptz default null
)
returns timestamptz
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_caller uuid;
  v_start  timestamptz;
begin
  v_caller := auth.uid();
  if v_caller is null then
    raise exception 'not authenticated' using errcode = 'P0001';
  end if;

  if not public.is_commissioner(p_group_id) then
    raise exception 'caller is not a commissioner of this group' using errcode = 'P0020';
  end if;

  -- Ruling 4: no move once the first eligible game has kicked off.
  if public.competition_start_frozen(p_group_id) then
    raise exception 'competition start is frozen: play has already begun'
      using errcode = 'P0031';
  end if;

  -- No backdating a chosen date; NULL resolves to now() (never past, race-free).
  if p_starts_at is not null and p_starts_at < now() then
    raise exception 'competition start cannot be in the past' using errcode = 'P0032';
  end if;

  v_start := coalesce(p_starts_at, now());

  update public.groups
  set competition_starts_at = v_start
  where id = p_group_id;

  return v_start;
end;
$$;

revoke execute on function public.set_competition_start(uuid, timestamptz) from public, anon;

-- file: grants/group_grants.sql
-- groups / group_memberships: authenticated access is gated by RLS.
-- Strip default public/anon ACLs first so anon has no Data API access.
revoke all on public.groups from public, anon;
revoke all on public.group_memberships from public, anon;

grant select on public.groups to authenticated;
-- SELECT only: all membership writes go through SECURITY DEFINER RPCs / service role.
-- Direct client INSERT is blocked by the no-client-write policy (25_policies_groups.sql).
grant select on public.group_memberships to authenticated;

grant execute on function public.is_member(uuid) to authenticated, service_role;

-- create_group is the only insert path into groups (RLS blocks direct client
-- inserts). It is SECURITY DEFINER and enforces the create-gate internally. The optional
-- second arg is the ADR-0037 competition start (NULL = start this week, from now).
grant execute on function public.create_group(text, timestamptz) to authenticated, service_role;

-- Commissioner management RPCs (ADR-0006, dec. 4 + 5): SECURITY DEFINER, caller-trust
-- verified internally; no direct client writes to groups.name or group_memberships.role.
grant execute on function public.rename_group(uuid, text)  to authenticated, service_role;
grant execute on function public.remove_member(uuid, uuid) to authenticated, service_role;
grant execute on function public.promote_member(uuid, uuid) to authenticated, service_role;
grant execute on function public.leave_group(uuid)         to authenticated, service_role;
grant execute on function public.mint_invite(uuid, integer, timestamptz) to authenticated, service_role;

-- set_competition_start (ADR-0037 ruling 4): commissioner moves when competition begins,
-- until the first eligible game kicks off. SECURITY DEFINER; commissioner + freeze + no-backdate
-- guards enforced internally. competition_start_frozen is the shared ruling-4 predicate, also
-- read by the commissioner console to show or hide the control.
grant execute on function public.set_competition_start(uuid, timestamptz) to authenticated, service_role;
grant execute on function public.competition_start_frozen(uuid)           to authenticated, service_role;

-- update_group_config (issue #154): commissioner edits per-group league rules
-- (grading_preset, scoring_rules.drop_worst_week / drop_worst_week_start_year,
-- ADR-0018). SECURITY DEFINER; commissioner check + ADR-0007 season-freeze
-- enforced internally. No direct client writes to group_config
-- (upd_group_config_no_client policy stays intact). group_active_season_settled
-- is the shared freeze helper, also called by the group page load to lock the UI selector.
grant execute on function public.update_group_config(uuid, text, boolean, int) to authenticated, service_role;
grant execute on function public.group_active_season_settled(uuid)        to authenticated, service_role;

-- group_config / group_week_overrides: authenticated read gated by RLS.
-- Client writes are blocked by policy; all writes go through service_role.
revoke all on public.group_config from public, anon;
revoke all on public.group_week_overrides from public, anon;

grant select on public.group_config to authenticated;
grant select on public.group_week_overrides to authenticated;

-- group_invites: commissioners manage invites, gated by RLS; no anon access.
revoke all on public.group_invites from public, anon;

grant select, insert, update on public.group_invites to authenticated;

grant execute on function public.is_commissioner(uuid) to authenticated, service_role;
grant execute on function public.redeem_invite(text) to authenticated, service_role;
-- preview_invite: read-only display state for /join/[code]; SECURITY DEFINER so
-- invitees can preview an invite the commissioner-only RLS would otherwise hide.
grant execute on function public.preview_invite(text) to authenticated, service_role;

-- comments / reactions: members read+write their group's rows, gated by RLS.
-- Strip default anon/public ACLs first (defense in depth alongside RLS).
revoke all on public.comments  from public, anon;
revoke all on public.reactions from public, anon;

grant select, insert, delete on public.comments  to authenticated;
grant select, insert, delete on public.reactions to authenticated;

